import java.util.*;

public List<Integer> addToArrayForm(int[] num, int k) {
    List<Integer> result = new ArrayList<>();
    int carry = k, i = num.length - 1;
    while (i >= 0 || carry > 0) {
        if (i >= 0) {
            carry += num[i--];
        }
        result.add(carry % 10);
        carry /= 10;
    }
    Collections.reverse(result);
    return result;
}
```


